@@ -0,0 +1,277 @@
+{
+  "session": {
+    "dmScope": "per-account-channel-peer",
+    "reset": {
+      "mode": "idle",
+      "idleMinutes": 2880
+    }
+  },
+  "update": {
+    "auto": {
+      "enabled": false
+    }
+  },
+  "tools": {
+    "profile": "full",
+    "deny": ["web_search", "browser", "canvas", "gateway", "image_generate"],
+    "exec": {
+      "host": "auto",
+      "security": "full",
+      "ask": "off",
+      "applyPatch": {
+        "enabled": false
+      },
+      "strictInlineEval": false
+    },
+    "web": {
+      "search": {
+        "enabled": false
+      }
+    },
+    "media": {
+      "audio": {
+        "enabled": true,
+        "models": [
+          { "provider": "zooclaw", "model": "Qwen/Qwen3-ASR-1.7B" }
+        ],
+        "scope": { "default": "allow" },
+        "attachments": { "mode": "all" }
+      }
+    }
+  },
+  "messages": {
+    "tts": {
+      "auto": "inbound",
+      "provider": "zooclaw",
+      "modelOverrides": {
+        "enabled": true
+      }
+    }
+  },
+  "models": {
+    "mode": "merge",
+    "providers": {
+      "openai": {
+        "baseUrl": "${LITELLM_API_BASE}/v1",
+        "apiKey": "${LITELLM_API_KEY}",
+        "auth": "api-key",
+        "api": "openai-completions",
+        "models": [
+          {
+            "id": "gpt-5.4",
+            "name": "GPT 5.4",
+            "input": ["text", "image"],
+            "contextWindow": 1050000,
+            "maxTokens": 128000,
+            "compat": { "supportsUsageInStreaming": true }
+          },
+          {
+            "id": "gemini-3-flash-preview",
+            "name": "Gemini 3 Flash",
+            "input": ["text", "image"],
+            "contextWindow": 1048576,
+            "maxTokens": 65535,
+            "compat": { "supportsUsageInStreaming": true }
+          },
+          {
+            "id": "kimi-k2.6",
+            "name": "Kimi K2.6",
+            "input": ["text", "image"],
+            "contextWindow": 262144,
+            "maxTokens": 262144,
+            "compat": { "supportsUsageInStreaming": true }
+          }
+        ]
+      },
+      "anthropic": {
+        "baseUrl": "${LITELLM_API_BASE}",
+        "apiKey": "${LITELLM_API_KEY}",
+        "auth": "api-key",
+        "api": "anthropic-messages",
+        "models": [
+          {
+            "id": "claude-sonnet-4-6",
+            "name": "Claude Sonnet 4.6",
+            "input": ["text", "image"],
+            "contextWindow": 200000,
+            "maxTokens": 64000,
+            "compat": { "supportsUsageInStreaming": true }
+          },
+          {
+            "id": "claude-haiku-4-5",
+            "name": "Claude Haiku 4.5",
+            "input": ["text", "image"],
+            "contextWindow": 200000,
+            "maxTokens": 32000,
+            "compat": { "supportsUsageInStreaming": true }
+          }
+        ]
+      }
+    }
+  },
+  "agents": {
+    "defaults": {
+      "heartbeat": {
+        "every": "55m",
+        "target": "last",
+        "lightContext": true,
+        "isolatedSession": true,
+        "model": "anthropic/claude-haiku-4-5"
+      },
+      "model": {
+        "primary": "anthropic/claude-sonnet-4-6",
+        "fallbacks": [
+          "openai/gpt-5.4",
+          "openai/gemini-3-flash-preview",
+          "openai/kimi-k2.6"
+        ]
+      },
+      "pdfModel": "anthropic/claude-sonnet-4-6",
+      "mediaMaxMb": 200,
+      "timeoutSeconds": 1800,
+      "llm": {
+        "idleTimeoutSeconds": 120
+      },
+      "compaction": {
+        "model": "anthropic/claude-haiku-4-5",
+        "reserveTokensFloor": 40000,
+        "timeoutSeconds": 900,
+        "memoryFlush": {
+          "enabled": true,
+          "softThresholdTokens": 10000
+        }
+      },
+      "memorySearch": {
+        "sources": ["memory", "sessions"],
+        "provider": "openai",
+        "remote": {
+          "baseUrl": "${LITELLM_API_BASE}/v1",
+          "apiKey": "${LITELLM_API_KEY}"
+        },
+        "model": "text-embedding-3-small",
+        "store": {
+          "fts": {
+            "tokenizer": "trigram"
+          }
+        },
+        "query": {
+          "hybrid": {
+            "enabled": true,
+            "vectorWeight": 0.7,
+            "textWeight": 0.3,
+            "candidateMultiplier": 4
+          }
+        }
+      }
+    }
+  },
+  "plugins": {
+    "entries": {
+      "acpx": {
+        "enabled": true,
+        "config": {
+          "command": "acpx",
+          "permissionMode": "approve-all"
+        }
+      },
+      "mattermost": { "enabled": true },
+      "telegram": { "enabled": true },
+      "discord": { "enabled": true },
+      "slack": { "enabled": true },
+      "diagnostics-otel": { "enabled": true },
+      "openclaw-tts": { "enabled": true },
+      "openclaw-asr": { "enabled": true },
+      "zooguardian": {
+        "enabled": true,
+        "config": {
+          "dryRun": true,
+          "filterToolInputs": true,
+          "filterToolOutputs": true,
+          "secrets": {
+            "enabled": true,
+            "action": "log",
+            "severityActions": {
+              "critical": "log",
+              "high": "log",
+              "medium": "log",
+              "low": "log"
+            }
+          },
+          "pii": {
+            "enabled": true,
+            "action": "log",
+            "severityActions": {
+              "critical": "log",
+              "high": "log",
+              "medium": "log",
+              "low": "log"
+            }
+          },
+          "destructive": {
+            "enabled": true,
+            "action": "log",
+            "severityActions": {
+              "critical": "log",
+              "high": "log",
+              "medium": "log",
+              "low": "log"
+            }
+          },
+          "logging": {
+            "logDetections": true,
+            "logLevel": "info"
+          }
+        }
+      }
+    }
+  },
+  "diagnostics": {
+    "enabled": true,
+    "otel": {
+      "enabled": true,
+      "endpoint": "http://otel-collector.monitoring:4318",
+      "protocol": "http/protobuf",
+      "serviceName": "openclaw-bot",
+      "traces": false,
+      "metrics": true,
+      "logs": false,
+      "sampleRate": 1.0,
+      "flushIntervalMs": 60000
+    }
+  },
+  "channels": {
+    "slack":    { "enabled": false, "accounts": {} },
+    "discord":  { "enabled": false, "accounts": {} },
+    "telegram": { "enabled": false, "accounts": {} }
+  },
+  "gateway": {
+    "bind": "lan",
+    "auth": {
+      "mode": "token",
+      "token": "${GATEWAY_TOKEN}"
+    },
+    "controlUi": {
+      "dangerouslyDisableDeviceAuth": true
+    },
+    "reload": {
+      "mode": "hot",
+      "deferralTimeoutMs": 300000
+    },
+    "webchat": {
+      "chatHistoryMaxChars": 12000
+    },
+    "channelStaleEventThresholdMinutes": 30,
+    "channelMaxRestartsPerHour": 10
+  },
+  "skills": {
+    "entries": {
+      "openai-image-gen":   { "enabled": false },
+      "openai-whisper-api": { "enabled": false },
+      "github":             { "enabled": false },
+      "gh-issues":          { "enabled": false }
+    }
+  },
+  "env": {
+    "vars": {}
+  }
+}
